#include <bits/stdc++.h>
#define int long long
#define ull unsigned long long
#define mk make_pair
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
struct node
{
    int d,c,p;
    bool operator < (const node &x) const
    {
        return d>x.d;
    }
};
CI MAXN=1e5+5;
int dis[MAXN][150],n,m,k;
vector<PII> g[MAXN];
void dijkstra(int s)
{
    cli(dis);
    priority_queue<node> q;
    q.push({0,0,s});
    dis[s][0]=0;
    wh(q.size())
    {
        int d=q.top().d;
        int c=q.top().c;
        int p=q.top().p;
        q.pop();
        if(d>dis[p][c])continue;
        FOI(e,g[p])
        {
            int v=e.fst;
            int w=e.snd;
            int nd=0;
            if(d>=w)
            {
                nd=dis[p][c]+1;
            }
            else
            {
                int x=(w-d+k-1)/k;
                nd=x*k+d+1;
            }
            int nc=(c+1)%k;
            if(nd<dis[v][nc])
            {
                dis[v][nc]=nd;
                q.push({nd,nc,v});
            }
        }
    }
}
signed main(void)
{
    n=read(),m=read(),k=read();
    FOR(i,1,m)
    {
        int u=read(),v=read(),w=read();
        g[u].pb(mk(v,w));
    }
    dijkstra(1);
    if(dis[n][0]>=llinf/2)NoAns
    else writeln(dis[n][0]);
    return false;
}
